-- ملء محتوى عنقود "فقه الأقليات" (fiqh-aqalliyat) — خمسة تصنيفات فرعية
-- draft بالكامل: العبادات والطعام (aqalliyat-ibadat)، العمل والمعاملات
-- (aqalliyat-amal-muamalat)، الأسرة وتعليم الأبناء (aqalliyat-usrah-abna)،
-- المواطنة والاندماج والعلاقات المجتمعية (aqalliyat-muwatana)، الضرورة
-- والحاجة واختلاف البلاد (aqalliyat-darura). كل تصنيف يحصل على درس واحد
-- (lessons + lesson_sections + lesson_citations)، بنفس أسلوب الدفعات
-- السابقة (body + examples).
-- المصدر المعتمد: يوسف القرضاوي "في فقه الأقليات المسلمة: حياة المسلمين
-- وسط المجتمعات الأخرى" (المصدر التأسيسي المعاصر الذي أرسى هذا الحقل
-- الفقهي ويغطي مباشرة الأبواب الخمسة أعلاه).
-- خمس آيات تحقَّقت حرفياً محليًا من artifacts/majalis/public/data/quran
-- عبر numberInSurah: المائدة 5 (طعام أهل الكتاب)، الجمعة 10 (الانتشار
-- طلبًا للرزق)، التحريم 6 (وقاية الأهل)، الممتحنة 8 (البر بغير
-- المحاربين)، البقرة 173 (الضرورة). خمسة أحاديث استُشهد بها، تحقَّقت
-- عبر WebSearch قبل الإدراج: «جمع بين الظهر والعصر... من غير خوف ولا
-- مطر... أراد أن لا يحرج أمته» عن ابن عباس (مسلم 705)، «ما أكل أحد
-- طعامًا قط خيرًا من أن يأكل من عمل يده، وإن نبي الله داود كان يأكل من
-- عمل يده» عن المقدام (البخاري 2072)، «كل مولود يولد على الفطرة فأبواه
-- يهودانه أو ينصرانه أو يمجسانه» عن أبي هريرة (متفق عليه، البخاري 1385
-- ومسلم 2658)، «ما زال جبريل يوصيني بالجار حتى ظننت أنه سيورثه» عن
-- عائشة (متفق عليه، البخاري 6014 ومسلم 2624)، «ما خُيِّر رسول الله بين
-- أمرين إلا اختار أيسرهما ما لم يكن إثمًا» عن عائشة (البخاري 3560).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الخمسة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) العبادات والطعام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8417a42e-5047-4e71-a257-8164063085bf' AND title='أحكام العبادة والطعام للمسلم في ديار غير المسلمين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام العبادة والطعام للمسلم في ديار غير المسلمين', 'بيان ضوابط رخصة الجمع بين الصلاتين للحاجة وأحكام طعام أهل الكتاب للمسلم المقيم في بلاد الأقلية', '8417a42e-5047-4e71-a257-8164063085bf', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'رخصة الجمع بين الصلاتين وحل طعام أهل الكتاب', 'يواجه المسلم المقيم بين ظهراني غير المسلمين ظروفًا خاصة تستدعي بيان أحكام دقيقة في بابي العبادة والطعام. ففي باب العبادة، أجاز فقهاء الأقليات المعاصرون - وعلى رأسهم يوسف القرضاوي في كتابه "في فقه الأقليات المسلمة" - الأخذ برخصة الجمع بين الصلاتين حال الحاجة الحقيقية كضيق أوقات العمل أو تعارضها مع مواقيت الصلاة، استنادًا إلى فعل النبي صلى الله عليه وسلم الجمع دون عذر السفر أو الخوف، رفعًا للحرج عن الأمة لا تهاونًا بالفريضة. وفي باب الطعام، أباح القرآن الكريم صراحة طعام أهل الكتاب للمسلمين، وهو أصل تُبنى عليه فتاوى إباحة الأكل من مطاعم غير المسلمين وأسواقهم إذا غلب على الظن حل الطعام أو كان خاليًا من اللحم أصلًا، دون تكلف السؤال أو التنقيب.', 1),
    (v_lesson, 'examples', 'الآية والحديث الأصل في البابين', 'قال تعالى: ﴿الْيَوْمَ أُحِلَّ لَكُمُ الطَّيِّبَاتُ وَطَعَامُ الَّذِينَ أُوتُوا الْكِتَابَ حِلٌّ لَّكُمْ وَطَعَامُكُمْ حِلٌّ لَّهُمْ﴾ (المائدة: 5)، أصّلت لحلّ طعام أهل الكتاب للمسلمين، وهو ما يعتمد عليه المسلم المقيم في بلاد غير إسلامية عند التعامل مع أسواقها ومطاعمها. وفي باب رخصة الجمع للحاجة، عن ابن عباس رضي الله عنهما أن رسول الله صلى الله عليه وسلم جمع بين الظهر والعصر والمغرب والعشاء بالمدينة من غير خوف ولا مطر، فقيل له في ذلك، فقال: أراد أن لا يحرج أمته (رواه مسلم 705). فدلّ الحديث على أن رفع الحرج مقصد شرعي معتبر يجيز الجمع للحاجة الحقيقية، وهو ما يُبنى عليه ترخيص جمع الصلاتين للمسلم الذي تتعارض أوقات عمله مع مواقيت الصلاة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'في فقه الأقليات المسلمة: حياة المسلمين وسط المجتمعات الأخرى — يوسف القرضاوي', 1);
  END IF;

  -- 2) العمل والمعاملات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b0d95578-77cc-47eb-a236-11d4de7245c8' AND title='ضوابط العمل والمعاملات المالية للمسلم في المجتمعات غير المسلمة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('ضوابط العمل والمعاملات المالية للمسلم في المجتمعات غير المسلمة', 'بيان الأصل الشرعي في طلب الرزق بين غير المسلمين وضوابط التعامل مع الأنظمة المصرفية المختلطة', 'b0d95578-77cc-47eb-a236-11d4de7245c8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الأصل في السعي على الرزق وضوابط الاضطرار للنظام المصرفي', 'الأصل في السعي على الرزق والعمل بين ظهراني غير المسلمين الإباحة والحث، لأن طلب الرزق عبادة إذا صحبته النية، ولم يفرّق الشرع فيه بين بلاد المسلمين وغيرها ما دام العمل في ذاته مباحًا. غير أن المسلم المقيم في تلك الديار يواجه تحديات خاصة في المعاملات المالية أبرزها شيوع القروض والودائع الربوية في النظام المصرفي السائد، فقرر فقهاء الأقليات المعاصرون - وعلى رأسهم القرضاوي - جواز الاضطرار إلى فتح حساب بنكي عادي إن تعذر وجود بديل إسلامي وكان لازمًا لقبض الراتب أو دفع الإيجار، ما لم يأخذ الفوائد الربوية لنفسه بل يتخلص منها في وجوه الخير العامة إن فُرضت عليه جبرًا. أما القرض الربوي لشراء المسكن فأجازه بعض المعاصرين للضرورة الحقيقية عند تعذر البديل بوصفه رخصة استثنائية لا يُتوسع فيها.', 1),
    (v_lesson, 'examples', 'الانتشار طلبًا للرزق والاعتماد على كسب اليد', 'قال تعالى: ﴿فَإِذَا قُضِيَتِ الصَّلَاةُ فَانتَشِرُوا فِي الْأَرْضِ وَابْتَغُوا مِن فَضْلِ اللَّهِ وَاذْكُرُوا اللَّهَ كَثِيرًا لَّعَلَّكُمْ تُفْلِحُونَ﴾ (الجمعة: 10)، أمرًا بالانتشار في الأرض طلبًا للرزق بعد أداء الفريضة، وهو أصل عام لا يخص بلاد المسلمين دون غيرها. وفي بيان قيمة الكسب من العمل الحلال، عن المقدام رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «ما أكل أحد طعامًا قط خيرًا من أن يأكل من عمل يده، وإن نبي الله داود عليه السلام كان يأكل من عمل يده» (رواه البخاري 2072). فضرب النبي صلى الله عليه وسلم المثل بنبي الله داود عليه السلام في الاعتماد على كسب اليد، وهو ما يوجّه المسلم المقيم بين غير المسلمين إلى تحرّي الكسب الحلال والاستقلال المالي قدر استطاعته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'في فقه الأقليات المسلمة: حياة المسلمين وسط المجتمعات الأخرى — يوسف القرضاوي', 1);
  END IF;

  -- 3) الأسرة وتعليم الأبناء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9822b259-3660-483a-88d8-d109a0671cba' AND title='تربية الأبناء والحفاظ على الهوية الإسلامية للأسرة المهاجرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تربية الأبناء والحفاظ على الهوية الإسلامية للأسرة المهاجرة', 'مسؤولية الوالدين في غرس العقيدة واللغة العربية والهوية الإسلامية في أبنائهم وسط مجتمع غير مسلم', '9822b259-3660-483a-88d8-d109a0671cba', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'البيت حصن الهوية والوسطية المطلوبة في التربية', 'تتضاعف مسؤولية الوالدين المسلمين في تربية أبنائهم حين يكون المحيط المدرسي والاجتماعي غير إسلامي في غالب مؤثراته، إذ يصبح البيت هو الحصن شبه الوحيد لغرس العقيدة والهوية. وقد أكد فقهاء الأقليات المعاصرون، وفي مقدمتهم القرضاوي، على وجوب تعليم الأبناء أصول العقيدة والعبادات وتحفيظهم من القرآن ما تيسّر، والحرص على تعلمهم اللغة العربية ولو بالمدارس التكميلية في عطلة نهاية الأسبوع، لأنها مفتاح فهم الدين وسبب رئيس من أسباب بقاء الهوية جيلاً بعد جيل. كما نبّهوا على خطورة ترك الأبناء بلا توجيه معتدل يوازن بين الانفتاح على مجتمعهم بالمعروف والحفاظ على الثوابت، لأن الإفراط في الانغلاق قد يدفعهم للتمرد وفقدان الهوية، بينما الإفراط في الذوبان يفقدهم إياها بطريق آخر.', 1),
    (v_lesson, 'examples', 'وقاية الأهل من النار وأثر تنشئة الوالدين على هوية الولد', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا قُوا أَنفُسَكُمْ وَأَهْلِيكُمْ نَارًا﴾ (التحريم: 6)، جعلت وقاية الأهل من النار مسؤولية مباشرة على رب الأسرة، وهي أصل يقوم عليه واجب التربية الدينية للأبناء أينما أقام المسلم. وفي بيان أثر تنشئة الوالدين على تدين الولد، عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «كل مولود يولد على الفطرة، فأبواه يهودانه أو ينصرانه أو يمجسانه» (متفق عليه، رواه البخاري 1385 ومسلم 2658). فبيّن الحديث أن أثر تنشئة الوالدين على دين الطفل وهويته أعظم من أي مؤثر آخر، وهو ما يحمّل الوالدين المسلمين المقيمين بين غير المسلمين مسؤولية مضاعفة في التربية الإيمانية داخل البيت.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'في فقه الأقليات المسلمة: حياة المسلمين وسط المجتمعات الأخرى — يوسف القرضاوي', 1);
  END IF;

  -- 4) المواطنة والاندماج والعلاقات المجتمعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6b96d4d4-c220-4ec7-91f9-412af9c7009c' AND title='المواطنة والاندماج الإيجابي وعلاقة المسلم بمجتمعه غير المسلم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المواطنة والاندماج الإيجابي وعلاقة المسلم بمجتمعه غير المسلم', 'الأصل الشرعي في البر والقسط مع غير المسلمين المسالمين والاندماج الإيجابي دون ذوبان في الهوية', '6b96d4d4-c220-4ec7-91f9-412af9c7009c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الاندماج الإيجابي بين الذوبان والانعزال', 'قرر فقهاء الأقليات المعاصرون أن الأصل في علاقة المسلم بمواطنيه وجيرانه من غير المسلمين في بلاد الإقامة هو البر والعدل والتعاون على الخير، لا العزلة ولا العداء، ما داموا مسالمين لم يقاتلوا المسلمين في دينهم ولم يخرجوهم من ديارهم. ودعا القرضاوي في كتابه إلى ما سمّاه "الاندماج الإيجابي"، وهو المشاركة الفاعلة في الحياة العامة كالعمل التطوعي والانخراط في الشأن المدني والوفاء بالتزامات المواطنة والقانون، مع التمسك بالثوابت العقدية والأخلاقية، تمييزًا له عن "الذوبان" الذي يفقد المسلم هويته و"الانعزال" الذي يحرمه فرصة تقديم صورة صحيحة عن الإسلام وتحقيق مصالح جماعته. وحسن الخلق مع الجار وإن اختلف دينه من أبرز مظاهر هذا البر المأمور به شرعًا.', 1),
    (v_lesson, 'examples', 'البر والقسط مع غير المحاربين وعموم حق الجوار', 'قال تعالى: ﴿لَا يَنْهَاكُمُ اللَّهُ عَنِ الَّذِينَ لَمْ يُقَاتِلُوكُمْ فِي الدِّينِ وَلَمْ يُخْرِجُوكُم مِّن دِيَارِكُمْ أَن تَبَرُّوهُمْ وَتُقْسِطُوا إِلَيْهِمْ ۚ إِنَّ اللَّهَ يُحِبُّ الْمُقْسِطِينَ﴾ (الممتحنة: 8)، أصّلت لجواز بل استحباب البر والقسط مع غير المسلمين المسالمين، وهي الآية الأصل التي يستند إليها فقهاء الأقليات في تقرير مبدأ التعايش الإيجابي. وفي بيان عظم حق الجار عمومًا، عن عائشة رضي الله عنها قالت: قال رسول الله صلى الله عليه وسلم: «ما زال جبريل يوصيني بالجار حتى ظننت أنه سيورثه» (متفق عليه، رواه البخاري 6014 ومسلم 2624). وقد استدل به فقهاء الأقليات على عموم حق الجوار وحسن المعاملة الذي لا يقتصر على المسلم دون غيره، بل يشمل كل جار بحكم الجوار المجرد.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'في فقه الأقليات المسلمة: حياة المسلمين وسط المجتمعات الأخرى — يوسف القرضاوي', 1);
  END IF;

  -- 5) الضرورة والحاجة واختلاف البلاد
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8e84d75e-7067-4203-a390-41da4bf73c5a' AND title='فقه الضرورة والحاجة وأثر اختلاف البلاد في الفتوى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فقه الضرورة والحاجة وأثر اختلاف البلاد في الفتوى', 'بيان قاعدتي الضرورة والحاجة وأثرهما في ترخص المسلم المقيم في بلاد غير إسلامية', '8e84d75e-7067-4203-a390-41da4bf73c5a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'قاعدتا الضرورة والحاجة وتغير الفتوى بتغير المكان', 'يقوم فقه الأقليات المسلمة على ركيزتين أصوليتين محكمتين: قاعدة "الضرورات تبيح المحظورات" وقاعدة "الحاجة تنزل منزلة الضرورة" في التخفيف لا في إباحة الحرام المطلق، مع اشتراط انضباطهما بقيدي التقدير بقدرهما وانتفاء البغي والعدوان. وقد بنى فقهاء الأقليات المعاصرون على هاتين القاعدتين طائفة من الفتاوى الخاصة بمن يعيش أقلية بين غير المسلمين، مراعين في ذلك مبدأ تغير الفتوى بتغير الزمان والمكان والعرف والحال الذي قرره ابن القيم في "إعلام الموقعين"، فما يُفتى به لمسلم يعيش في مجتمع إسلامي قد يختلف الترخص فيه لمن يعيش في مجتمع تتعذر فيه بعض شعائره أو تختلف أعرافه، دون أن يعني هذا تبديلاً للأحكام القطعية الثابتة، بل تنزيلاً فقهيًا مراعيًا لواقع كل فئة وظرفها.', 1),
    (v_lesson, 'examples', 'آية الضرورة وهدي النبي في اختيار الأيسر', 'قال تعالى: ﴿إِنَّمَا حَرَّمَ عَلَيْكُمُ الْمَيْتَةَ وَالدَّمَ وَلَحْمَ الْخِنزِيرِ وَمَا أُهِلَّ بِهِ لِغَيْرِ اللَّهِ ۖ فَمَنِ اضْطُرَّ غَيْرَ بَاغٍ وَلَا عَادٍ فَلَا إِثْمَ عَلَيْهِ ۚ إِنَّ اللَّهَ غَفُورٌ رَّحِيمٌ﴾ (البقرة: 173)، أصّلت لقاعدة الضرورة بقيديها: انتفاء البغي والعدوان، وهي الأصل القرآني الذي تُبنى عليه سائر تطبيقات فقه الضرورة والحاجة في فقه الأقليات. وفي بيان هدي النبي صلى الله عليه وسلم عند تعدد الخيارات المباحة، عن عائشة رضي الله عنها قالت: «ما خُيِّر رسول الله صلى الله عليه وسلم بين أمرين إلا اختار أيسرهما ما لم يكن إثمًا» (رواه البخاري 3560). فدلّ الحديث على أن التيسير عند تعدد الوجوه المشروعة هدي نبوي، وهو ما يستأنس به في ترجيح الأقوال الأيسر عند الإفتاء لمن يعيش ظروف الأقلية واختلاف البلاد، ما لم يفضِ ذلك إلى ارتكاب محرم قطعي.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'في فقه الأقليات المسلمة: حياة المسلمين وسط المجتمعات الأخرى — يوسف القرضاوي', 1);
  END IF;

